import{_ as s,o as i,c as t,a2 as a}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"Docs Site Deployment","description":"","frontmatter":{},"headers":[],"relativePath":"reference/docs-site-deployment.md","filePath":"reference/docs-site-deployment.md","lastUpdated":null}'),o={name:"reference/docs-site-deployment.md"};function n(l,e,d,c,r,p){return i(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="docs-site-deployment" tabindex="-1">Docs Site Deployment <a class="header-anchor" href="#docs-site-deployment" aria-label="Permalink to &quot;Docs Site Deployment&quot;">​</a></h1><p>The documentation site source lives in <code>docs.autofac.de/</code>. It builds to static files and is designed for GitHub Pages.</p><h2 id="local-commands" tabindex="-1">Local commands <a class="header-anchor" href="#local-commands" aria-label="Permalink to &quot;Local commands&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs.autofac.de</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ci</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preview</span></span></code></pre></div><h2 id="github-pages-workflow" tabindex="-1">GitHub Pages workflow <a class="header-anchor" href="#github-pages-workflow" aria-label="Permalink to &quot;GitHub Pages workflow&quot;">​</a></h2><p>The workflow at <code>.github/workflows/docs-pages.yml</code>:</p><ol><li>Runs on changes to <code>docs.autofac.de/**</code> and the workflow file.</li><li>Installs docs dependencies with <code>npm ci</code>.</li><li>Builds the site with <code>npm run build</code>.</li><li>Uploads <code>docs.autofac.de/.vitepress/dist</code>.</li><li>Deploys the artifact to GitHub Pages on non-pull-request events.</li></ol><p>Pull requests build the docs but do not deploy them.</p><h2 id="repository-settings" tabindex="-1">Repository settings <a class="header-anchor" href="#repository-settings" aria-label="Permalink to &quot;Repository settings&quot;">​</a></h2><p>In GitHub repository settings:</p><ol><li>Open Pages.</li><li>Set Build and deployment source to GitHub Actions.</li><li>Configure the custom domain as <code>docs.autofac.de</code>.</li><li>Enable HTTPS when GitHub allows it.</li></ol><p>GitHub&#39;s Pages settings or API must own the custom domain setting. A <code>CNAME</code> file in the artifact is useful documentation, but for an Actions-backed Pages deployment it does not by itself configure the repository custom domain.</p><h2 id="dns" tabindex="-1">DNS <a class="header-anchor" href="#dns" aria-label="Permalink to &quot;DNS&quot;">​</a></h2><p>For the <code>docs.autofac.de</code> subdomain, create a DNS <code>CNAME</code> record that points to the GitHub Pages default domain for the organization or user, normally:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>isartor-ai.github.io</span></span></code></pre></div><p>Do not include the repository name in the DNS target.</p><p>DNS changes can take time to propagate. Verify the record before enabling production links.</p><h2 id="build-output" tabindex="-1">Build output <a class="header-anchor" href="#build-output" aria-label="Permalink to &quot;Build output&quot;">​</a></h2><p>VitePress writes generated files to:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docs.autofac.de/.vitepress/dist</span></span></code></pre></div><p>That directory is ignored by git and should not be committed.</p><h2 id="release-checklist" tabindex="-1">Release checklist <a class="header-anchor" href="#release-checklist" aria-label="Permalink to &quot;Release checklist&quot;">​</a></h2><ul><li><code>npm ci</code> passes in <code>docs.autofac.de</code>.</li><li><code>npm run build</code> passes with no broken internal links.</li><li>Local preview loads home, manual, admin, developer, and reference pages.</li><li>GitHub repository Pages source is GitHub Actions.</li><li>Custom domain is configured in repository settings.</li><li>DNS points <code>docs.autofac.de</code> to the GitHub Pages default domain.</li><li>HTTPS is enforced after the certificate is available.</li></ul>`,23)])])}const k=s(o,[["render",n]]);export{u as __pageData,k as default};
